import{_ as t,o,c as a,ae as n}from"./chunks/framework.CyZiF_rV.js";const i="/ksef-docs/assets/hwm.CnKORmUR.png",r="/ksef-docs/assets/hwm-1.Bdx9PjiU.png",s="/ksef-docs/assets/hwm-2.CZj0KUSn.png",w=JSON.parse('{"title":"High Water Mark (HWM)","description":"","frontmatter":{},"headers":[],"relativePath":"en/pobieranie-faktur/hwm.md","filePath":"en/pobieranie-faktur/hwm.md"}'),c={name:"en/pobieranie-faktur/hwm.md"};function l(d,e,h,m,u,p){return o(),a("div",null,[...e[0]||(e[0]=[n('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/pobieranie-faktur/hwm.md" target="_blank" rel="noreferrer">pobieranie-faktur/hwm.md</a></p></blockquote><h1 id="high-water-mark-hwm" tabindex="-1">High Water Mark (HWM) <a class="header-anchor" href="#high-water-mark-hwm" aria-label="Permalink to &quot;High Water Mark (HWM)&quot;">​</a></h1><p>25.11.2025</p><p>The High Water Mark (HWM) mechanism describes how KSeF manages data completeness over time for the <code>PermanentStorage</code> date.</p><p>At any given moment, the system knows a point in time (<code>HWM</code>) up to which it has certainty that all invoices have been saved and no new documents will appear with a <code>PermanentStorage</code> date earlier than or equal to this moment.</p><p><img src="'+i+'" alt="HWM"></p><ul><li>For time ≤ <code>HWM</code> - all invoices with <code>PermanentStorage</code> date in this range have already been permanently saved in KSeF. The system guarantees that in the future no new invoice will appear with <code>PermanentStorage</code> date ≤ <code>HWM</code>.</li><li>In the range (<code>HWM</code>, <code>Now</code>): <ul><li>some invoices are already visible and can be returned in a query,</li><li>due to the asynchronous and multi-threaded nature of the saving process, new invoices may still appear in this range, i.e., with <code>PermanentStorage</code> date falling within the range (<code>HWM</code>, <code>Now</code>].</li></ul></li></ul><p>Conclusion:</p><ul><li>everything that is ≤ <code>HWM</code> can be treated as a <strong>closed</strong> and <strong>complete</strong> set,</li><li>everything that is &gt; <code>HWM</code> is <strong>potentially incomplete</strong> and requires careful handling during synchronization.</li></ul><h2 id="scenario-1-synchronization-only-to-hwm" tabindex="-1">Scenario 1 - synchronization &quot;only to HWM&quot; <a class="header-anchor" href="#scenario-1-synchronization-only-to-hwm" aria-label="Permalink to &quot;Scenario 1 - synchronization &quot;only to HWM&quot;&quot;">​</a></h2><p><img src="'+r+'" alt="HWM-1"></p><p>The system retrieves invoices with each query <strong>from the &quot;last known point&quot; only up to the current <code>HWM</code> value</strong>. The new <code>HWM</code> value becomes the beginning of the next range.</p><p>Advantages:</p><ul><li>data up to <code>HWM</code> is definitive - no need to recheck the same range,</li><li>the number of duplicates between consecutive retrievals is minimal.</li></ul><p>Consequences:</p><ul><li>some of the newest invoices from the range <code>(HWM, Now]</code> are not visible in the local system - they will appear only after <code>HWM</code> moves forward in the next cycle.</li></ul><p>This scenario is recommended for incremental, automatic data synchronization where optimization of traffic and minimization of duplicates is more important than immediate availability of the newest invoices.</p><h2 id="scenario-2-synchronization-to-now" tabindex="-1">Scenario 2 - synchronization &quot;to Now&quot; <a class="header-anchor" href="#scenario-2-synchronization-to-now" aria-label="Permalink to &quot;Scenario 2 - synchronization &quot;to Now&quot;&quot;">​</a></h2><p><img src="'+s+'" alt="HWM-2"></p><p>The system integrating with KSeF performs cyclical, incremental queries <strong>from the last starting point all the way to <code>Now</code></strong> and saves all returned invoices, including those from the range <code>(HWM, Now]</code>.</p><p>Since data in this range may be incomplete, <strong>the next query repeats part of the range</strong> - at least from the previous <code>HWM</code> to the new <code>Now</code>. Deduplication on the local system side is necessary (e.g., by KSeF number).</p><p>Advantages:</p><ul><li>the local system (and user) sees the newest invoices as quickly as possible, without waiting for <code>HWM</code> to &quot;catch up&quot; to them.</li></ul><p>Consequences:</p><ul><li>the range <code>(HWM, Now]</code> must be checked again in the next query,</li><li>duplicates will appear that need to be removed on the local system side.</li></ul><p>The same mechanism can also be used <strong>ad hoc</strong>, when a user manually requests data refresh - the system then retrieves &quot;here and now&quot; the newest available invoices from the last known date up to <code>Now</code>.</p><h2 id="related-documents" tabindex="-1">Related documents <a class="header-anchor" href="#related-documents" aria-label="Permalink to &quot;Related documents&quot;">​</a></h2><ul><li><a href="./przyrostowe-pobieranie-faktur.html">Incremental invoice retrieval</a></li></ul>',28)])])}const f=t(c,[["render",l]]);export{w as __pageData,f as default};
